126→              <Route path='freedom-wall' element={<FreedomWallPage/>}/>
127→              <Route path='contentViewer' element={<ContentView/>}/>
128→              <Route path='post/:journalId' element={<ContentView/>}/>
129→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
