132→              <Route path='opinions'element={<OpinionsPage/>}/>
133→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
134→
135→              <Route path='collections' element={<Collections/>}/>
136→              <Route path='collectionCards' element={<CollectionJournals/>}/>
137→              <Route path='settings' element={<SettingsPage/>}/>
138→
139→              {/* Stories routes */}
140→              <Route path='stories' element={<StoryBrowser/>}/>
141→              <Route path='stories/library' element={<StoryLibrary/>}/>
142→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
143→              <Route path='stories/new' element={<StoryEditor/>}/>
144→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
145→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
146→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
147→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
148→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
149→
150→              {/* route for nested notifications */}
151→              <Route path='notifications' element={<Notifications/>}>
152→                <Route index element={<NotificationCards/>}/>
153→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
154→              </Route>  
155→            </Route>   
156→
157→            <Route path='/universe' element={<Universe/>}/>
158→
159→            <Route path='/login' element={<LoginPage/>}/>
160→            <Route path='/signUp' element={<SignUp/>}/>
161→          </Routes>
162→        </Suspense>
163→      </BrowserRouter>
164→    </LexicalComposer>
165→    </>
166→  )
167→}
